s:script.c:code:
import com.evolveum.midpoint.xml.ns._public.common.common_3.UserType;
import javax.xml.namespace.QName;

def user = input;
def uoid = user.getOid();
def uname = user.getName()?.getOrig();

// 1) leer photoUrl (extension/upeu:photoUrl)
def urlStr = null;
try {
    def val = basic.getExtensionPropertyValue(user, new QName('urn:upeu:midpoint:local', 'photoUrl'));
    if (val != null) urlStr = val.toString();
} catch (Exception e) { log.warn('PHOTOFIX: error leyendo photoUrl de {}: {}', uname, e.message); return; }

if (urlStr == null || urlStr.trim().isEmpty()) { return; }
urlStr = urlStr.trim();

// 2) idempotencia: si ya hay foto, skip (igual que Bloque I condicion jpegPhoto==null)
if (user.getJpegPhoto() != null) { return; }

// 3) fetch HTTP (replica Bloque I; timeouts 800/2500 para MinIO LAN; 404 → skip)
try {
    def conn = (java.net.HttpURLConnection) new java.net.URL(urlStr).openConnection();
    conn.setConnectTimeout(800);
    conn.setReadTimeout(2500);
    conn.setRequestMethod('GET');
    conn.setRequestProperty('User-Agent', 'MidPoint-UPeU-IGA/1.0');
    def status = conn.getResponseCode();
    if (status != 200) { log.info('PHOTOFIX: HTTP {} {} ({})', status, uname, uoid); return; }
    def is = conn.getInputStream();
    def baos = new java.io.ByteArrayOutputStream();
    def buf = new byte[8192]; int n;
    while ((n = is.read(buf)) != -1) baos.write(buf, 0, n);
    is.close();
    def bytes = baos.toByteArray();
    if (bytes.length == 0) { log.info('PHOTOFIX: empty body {} ({})', uname, uoid); return; }

    // 4) escribir jpegPhoto DIRECTO al repo (raw → sin clockwork, sin proyeccion Entra/LDAP/Koha)
    def delta = midpoint.prismContext.deltaFor(UserType.class)
        .item(UserType.F_JPEG_PHOTO).replaceRealValues(java.util.Collections.singletonList(bytes)).asObjectDelta(uoid);
    def meoClass = Class.forName('com.evolveum.midpoint.model.api.ModelExecuteOptions');
    def opts = meoClass.getMethod('create').invoke(null);
    opts = opts.getClass().getMethod('raw').invoke(opts);
    midpoint.executeChanges([delta] as java.util.Collection, opts);
    log.info('PHOTOFIX OK: {} ({}) <- {} bytes', uname, uoid, bytes.length);
} catch (Exception e) {
    log.warn('PHOTOFIX: error fetch {} para {} ({}): {}', urlStr, uname, uoid, e.message);
}
